class FileSystem:
    def __init__(self):
        self.root = {'': {}}
    def _find(self, path):
        curr = self.root['']; pts = path.split('/')[1:]
        for p in pts:
            if not p: continue
            curr = curr[p]
        return curr
    def ls(self, path):
        curr = self._find(path)
        if isinstance(curr, str): return [path.split('/')[-1]]
        return sorted(curr.keys())
    def mkdir(self, path):
        curr = self.root['']; pts = path.split('/')[1:]
        for p in pts:
            if not p: continue
            if p not in curr: curr[p] = {}
            curr = curr[p]
    def addContentToFile(self, path, content):
        curr = self.root['']; pts = path.split('/')[1:]
        for p in pts[:-1]:
            if not p: continue
            curr = curr[p]
        if pts[-1] not in curr: curr[pts[-1]] = ''
        curr[pts[-1]] += content
    def readContentFromFile(self, path):
        return self._find(path)

